<?php/** * Created by PhpStorm. * User: spyros * Date: 12/27/14 * Time: 9:37 PM */class Controller_Admin_Globalsettings extends Controller_Admin{    public function action_index(){        if (!Auth::has_access('global_settings.read')){            Session::set_flash('error', e('You do not have access to this function!'));            Response::redirect('admin');        }        $old_settings = Model_Globalsetting::find('last');        $data=array('settings' => $old_settings);        $this->template->title = "Global Settings";        $this->template->css = array(            'vendor/jquery-ui/ui-lightness/jquery-ui-1.10.4.min.css',            'globalsettings.css'        );        $this->template->js = array(            'vendor/jquery-ui/jquery-ui-1.10.4.min.js',            'globalsettings.js'        );        if (Input::method() == 'POST' && Security::check_token()) {            $val = Model_Globalsetting::validate('edit');            if ($val->run()) {                $settings = Model_Globalsetting::find('last');                $settings->set(array(                    'linkexpirationdate'=> Input::post('linkexpirationdate'),                    'alllinksopen'=> Input::post('alllinksopen'),                    'emaildriver'=>$settings->emaildriver,     //Input::post('emaildriver'),                    'emailpriority'=>$settings->emailpriority,     //Input::post('emailpriority'),                    'emailhtml'=>$settings->emailhtml,     //Input::post('emailhtml'),                    'emailcharset'=>$settings->emailcharset,     //Input::post('emailcharset'),                    'emailencoding'=>$settings->emailencoding,     //Input::post('emailencoding'),                    'emailfrom'=>$settings->emailfrom,     //Input::post('emailfrom'),                    'emailname'=>$settings->emailname,     //Input::post('emailname'),                    'emailreturn'=>$settings->emailreturn,     //Input::post('emailreturn'),                    'emailpathtosendmail'=>$settings->emailpathtosendmail,     //Input::post('emailpathtosendmail'),                    'emailsmtphost'=>$settings->emailsmtphost,     //Input::post('emailsmtphost'),                    'emailsmtpport'=>$settings->emailsmtpport,     //Input::post('emailsmtpport'),                    'emailsmtpusername'=>$settings->emailsmtpusername,     //Input::post('emailsmtpusername'),                    'emailsmtppassword'=>$settings->emailsmtppassword,     //Input::post('emailsmtppassword'),                    'emailsmtptimeout'=>$settings->emailsmtptimeout,     //Input::post('emailsmtptimeout'),                    'newline'=>$settings->newline,     //Input::post('newline'),                    'overridelinkexpirationdate'=> Input::post('overridelinkexpirationdate'),                ));                if ($settings){                    try{                        $settings->save();                        Session::set_flash('success', e('Settings saved!'));                        Response::redirect('admin/globalsettings/index');                    }catch (\Database_Exception $e){                        Session::set_flash('error', e('Could not save settings! '.$e->getMessage()));                    }                } else {                    Session::set_flash('error', e('Could not save settings!'));                }            } else {                Session::set_flash('error', $val->error());            }        }        $this->template->content = View::forge('admin/globalsettings/index', $data);    }    public function action_enable(){        if (!Auth::has_access('global_settings.update')){            Session::set_flash('error', e('You do not have access to this function!'));            Response::redirect('admin');        }        $this->template->title = "Global Settings";            /*            $settings = Model_Globalsetting::find('last');            Config::load('email','custom',true,true);                                     Config::set('custom.defaults.driver',$settings->emaildriver);            Config::set('custom.defaults.is_html',$settings->emailhtml?true:false);            Config::set('custom.defaults.charset',$settings->emailcharset);            Config::set('custom.defaults.encoding',$settings->emailencoding);            Config::set('custom.defaults.priority',$settings->emailpriority);            Config::set('custom.defaults.newline',$settings->newline);                        //from            Config::set('custom.defaults.from.email',$settings->emailfrom);            Config::set('custom.defaults.from.name',$settings->emailname);            Config::set('custom.defaults.return_path',$settings->emailreturn);            Config::set('custom.defaults.sendmail_path',$settings->emailpathtosendmail);            //smtp            Config::set('custom.defaults.smtp.host',$settings->emailsmtphost);            Config::set('custom.defaults.smtp.port',$settings->emailsmtpport);            Config::set('custom.defaults.smtp.username',$settings->emailsmtpusername);            Config::set('custom.defaults.smtp.password',$settings->emailsmtppassword);            Config::set('custom.defaults.smtp.timeout',$settings->emailsmtptimeout);            try{                Config::save('email','custom');                Session::set_flash('success', e('Settings loaded!'));                Response::redirect('admin/globalsettings/index');            }catch (\Exception $e){                Session::set_flash('error', e('Could not load settings! '.$e->getMessage()));                Response::redirect('admin');            }            */        Response::redirect('admin/globalsettings');    }}